@OptIn(ExperimentalSharedTransitionApi::class, ExperimentalMaterial3Api::class)
@Composable
fun MediaViewerScreen(
	    mediaId: Long,
	        navController: NavController,
	            sharedTransitionScope: SharedTransitionScope,
	                animatedVisibilityScope: AnimatedVisibilityScope
	                ) {
	                	    val context = LocalContext.current
	                	        val repository = remember { MediaRepository(context, LunaDatabase.getDatabase(context)) }
	                	            val viewModel = remember { ViewerViewModel(repository) }

	                	                    // Untuk demo sederhana, kita asumsikan list media didapat dari repository
	                	                        // Pada app produksi, gunakan PagingData yang sama atau pass list id
	                	                            val scope = rememberCoroutineScope()
	                	                                var showUI by remember { mutableStateOf(true) }
	                	                                    val sheetState = rememberModalBottomSheetState()
	                	                                        var showExif by remember { mutableStateOf(false) }

	                	                                            // Auto-hide UI
	                	                                                LaunchedEffect(showUI) {
	                	                                                	        if (showUI) {
	                	                                                	        	            delay(3000)
	                	                                                	        	                        showUI = false
	                	                                                	        	                                }
	                	                                                	        	                                    }

	                	                                                	        	                                        Box(
	                	                                                	        	                                        	        modifier = Modifier
	                	                                                	        	                                        	                    .fillMaxSize()
	                	                                                	        	                                        	                                .background(Color.Black)
	                	                                                	        	                                        	                                            .pointerInput(Unit) {
	                	                                                	        	                                        	                                            	                detectTapGestures(onTap = { showUI = !showUI })
	                	                                                	        	                                        	                                            	                            }
	                	                                                	        	                                        	                                            	                                ) {
	                	                                                	        	                                        	                                            	                                	        // Konten utama: Untuk saat ini kita tampilkan single item berdasarkan ID
	                	                                                	        	                                        	                                            	                                	                // (Idealnya menggunakan HorizontalPager dengan list dari repository)

	                	                                                	        	                                        	                                            	                                	                                // Simulasi media (ambil dari DB)
	                	                                                	        	                                        	                                            	                                	                                        var currentMedia by remember { mutableStateOf<MediaItem?>(null) }
	                	                                                	        	                                        	                                            	                                	                                                LaunchedEffect(mediaId) {
	                	                                                	        	                                        	                                            	                                	                                                	            // Logic ambil single item by ID
	                	                                                	        	                                        	                                            	                                	                                                	                    }

	                	                                                	        	                                        	                                            	                                	                                                	                            currentMedia?.let { media ->
	                	                                                	        	                                        	                                            	                                	                                                	                                        with(sharedTransitionScope) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                Box(modifier = Modifier.fillMaxSize()) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    if (media.isVideo) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                        VideoPlayer(uri = media.uri.toString(), isPlaying = true)
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            } else {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        AsyncImage(
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                            model = media.uri,
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                        contentDescription = null,
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                    modifier = Modifier
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                    .fillMaxSize()
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    .sharedElement(
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                    rememberSharedContentState(key = "media-${media.id}"),
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                        animatedVisibilityScope = animatedVisibilityScope
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                        ),
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                    contentScale = ContentScale.Fit
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                            )
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                }
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                }
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                            }

	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                        // Top Bar
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    AnimatedVisibility(
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                visible = showUI,
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                enter = slideInVertically() + fadeIn(),
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                exit = slideOutVertically() + fadeOut()
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            ) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                TopAppBar(
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    title = {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                            Text(FormatUtil.formatDate(media.dateTaken), style = MaterialTheme.typography.labelLarge)
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                        Text(FormatUtil.formatDuration(media.duration), style = MaterialTheme.typography.bodySmall)
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                }
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                    },
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        navigationIcon = {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        IconButton(onClick = { navController.popBackStack() }) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                            Icon(Icons.Default.ArrowBack, contentDescription = null, tint = Color.White)
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                    }
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                        },
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            actions = {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        IconButton(onClick = { /* Share */ }) {
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                            Icon(Icons.Default.Share, contentDescription = null, tint = Color.White)
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                    }
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                        },
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                            colors = TopAppBarDefaults.topAppBarColors(containerColor = Color.Black.copy(alpha = 0.4f), titleContentColor = Color.White)
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                            )
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                                        }

	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                                                    // Bottom Bar
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                                                                AnimatedVisibility(
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                                                                	                visible = showUI,
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                                                                	                                modifier = Modifier.align(Alignment.BottomCenter),
	                	                                                	        	                                        	                                            	                                	                                                	                                        	                	                    	                                            	                        	                                                                                                                                                    	                                                                                                                                                                                                                                    	                                                            	                	                    	                        	                                                                                                                        	                        	                                                                                            	                        	                                                                                                                                                	                                                enter = slideInVertically(initialOffsetY = { it }) + fadeIn(),
